import React, { useState, useEffect } from 'react';
import { Link, useLocation } from 'react-router-dom';

const Header = () => {
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [isScrolled, setIsScrolled] = useState(false);
  const location = useLocation();

  useEffect(() => {
    const handleScroll = () => {
      setIsScrolled(window.scrollY > 100);
    };

    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const toggleMenu = () => {
    setIsMenuOpen(!isMenuOpen);
  };

  const closeMenu = () => {
    setIsMenuOpen(false);
  };

  const isActive = (path) => {
    if (path === '/' && location.pathname === '/') return true;
    if (path !== '/' && location.pathname.startsWith(path)) return true;
    return false;
  };

  return (
    <header className={`bg-white shadow-md fixed top-0 w-full z-50 transition-all duration-300 ${
      isScrolled ? 'shadow-xl' : ''
    }`}>
      <div className="max-w-7xl mx-auto px-5">
        <div className="flex justify-between items-center py-4">
          <Link to="/" className="flex items-center text-2xl font-bold text-fresh-green">
            <i className="fas fa-leaf mr-2 text-3xl"></i>
            <span>24*7 Fresh Store</span>
          </Link>

          <nav className="hidden md:block">
            <ul className="flex space-x-8">
              <li>
                <Link 
                  to="/" 
                  className={`text-gray-700 hover:text-fresh-green font-medium transition-colors ${
                    isActive('/') ? 'text-fresh-green' : ''
                  }`}
                >
                  Home
                </Link>
              </li>
              <li>
                <Link 
                  to="/vegetables" 
                  className={`text-gray-700 hover:text-fresh-green font-medium transition-colors ${
                    isActive('/vegetables') ? 'text-fresh-green' : ''
                  }`}
                >
                  Vegetables
                </Link>
              </li>
              <li>
                <Link 
                  to="/fruits" 
                  className={`text-gray-700 hover:text-fresh-green font-medium transition-colors ${
                    isActive('/fruits') ? 'text-fresh-green' : ''
                  }`}
                >
                  Fruits
                </Link>
              </li>
              <li>
                <Link 
                  to="/prices" 
                  className={`text-gray-700 hover:text-fresh-green font-medium transition-colors ${
                    isActive('/prices') ? 'text-fresh-green' : ''
                  }`}
                >
                  Today's Prices
                </Link>
              </li>
              <li>
                <a 
                  href="/#contact" 
                  className="text-gray-700 hover:text-fresh-green font-medium transition-colors"
                >
                  Contact
                </a>
              </li>
            </ul>
          </nav>

          <button 
            className="md:hidden text-2xl cursor-pointer"
            onClick={toggleMenu}
            aria-label="Toggle menu"
          >
            <i className={`fas ${isMenuOpen ? 'fa-times' : 'fa-bars'}`}></i>
          </button>
        </div>

        {/* Mobile menu */}
        {isMenuOpen && (
          <div className="md:hidden absolute top-full left-0 w-full bg-white shadow-lg">
            <ul className="flex flex-col p-4 space-y-4">
              <li>
                <Link 
                  to="/" 
                  className="text-gray-700 hover:text-fresh-green font-medium transition-colors block"
                  onClick={closeMenu}
                >
                  Home
                </Link>
              </li>
              <li>
                <Link 
                  to="/vegetables" 
                  className="text-gray-700 hover:text-fresh-green font-medium transition-colors block"
                  onClick={closeMenu}
                >
                  Vegetables
                </Link>
              </li>
              <li>
                <Link 
                  to="/fruits" 
                  className="text-gray-700 hover:text-fresh-green font-medium transition-colors block"
                  onClick={closeMenu}
                >
                  Fruits
                </Link>
              </li>
              <li>
                <Link 
                  to="/prices" 
                  className="text-gray-700 hover:text-fresh-green font-medium transition-colors block"
                  onClick={closeMenu}
                >
                  Today's Prices
                </Link>
              </li>
              <li>
                <a 
                  href="/#contact" 
                  className="text-gray-700 hover:text-fresh-green font-medium transition-colors block"
                  onClick={closeMenu}
                >
                  Contact
                </a>
              </li>
            </ul>
          </div>
        )}
      </div>
    </header>
  );
};

export default Header;
